#!/usr/bin/env node
// Bundle quizzes/*.json into a single loadable .js file.
//
// Why: modern browsers block fetch() of local JSON files when the host page
// is opened via file:// (no server). The notebook's README says double-clicking
// any page should work, so the quiz widget can't rely on fetch alone.
// A <script src="./quizzes/bundle.js"> tag works from file:// and exposes the
// quiz banks as a window global (window.MVQuizBank).
//
// Usage:  node scripts/build-quizzes-bundle.mjs
// Output: quizzes/bundle.js (overwritten)
//
// Run this whenever a quizzes/*.json file changes.

import { readFileSync, readdirSync, writeFileSync, statSync } from 'node:fs';
import { dirname, join, resolve, basename, extname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const repoRoot = resolve(dirname(__filename), '..');
const quizzesDir = join(repoRoot, 'quizzes');

const bank = {};
let count = 0, questions = 0;
for (const entry of readdirSync(quizzesDir)) {
  if (extname(entry) !== '.json') continue;
  const full = join(quizzesDir, entry);
  if (!statSync(full).isFile()) continue;
  const topic = basename(entry, '.json');
  const data = JSON.parse(readFileSync(full, 'utf8'));
  bank[topic] = data;
  count++;
  for (const q of Object.values(data.quizzes || {})) {
    questions += (q.questions?.length || 0);
  }
}

const outPath = join(quizzesDir, 'bundle.js');
const body = JSON.stringify(bank, null, 2);
const js =
`// Auto-generated by scripts/build-quizzes-bundle.mjs — DO NOT EDIT.
// Regenerate with:  node scripts/build-quizzes-bundle.mjs
// Source of truth: quizzes/*.json (one per topic).
window.MVQuizBank = ${body};
`;

writeFileSync(outPath, js);
console.log(`wrote ${outPath} — ${count} topic(s), ${questions} question(s)`);
